// ========================================
// Process Video Interview Trigger Input
// ========================================
const request = $input.first().json;

if (request.httpMethod === 'OPTIONS' || request.method === 'OPTIONS') {
  return [{ json: { message: 'CORS preflight successful' } }];
}

let body;
try {
  body = typeof request.body === 'string' ? JSON.parse(request.body) : (request.body || {});
} catch (error) {
  return [{
    json: {
      success: false,
      error: 'invalid_request_body',
      message: 'Request body must be valid JSON',
      status: 400
    }
  }];
}

const jobPositionId = body.jobPositionId || body.job_position_id || body.jid;
const appBaseUrl = (body.appBaseUrl || body.app_base_url || 'http://localhost:5173').replace(/\/$/, '');
const minMcqScore = Number(body.minMcqScore || body.min_mcq_score || 80);

if (!jobPositionId) {
  return [{
    json: {
      success: false,
      error: 'missing_job_position_id',
      message: 'Provide jobPositionId (or job_position_id/jid) to generate video interviews.',
      status: 400
    }
  }];
}

return [{
  json: {
    jobPositionId,
    appBaseUrl,
    minMcqScore,
    triggeredAt: new Date().toISOString(),
    workflowStage: 'video_interview_generation_from_mcq',
    nextStep: 'Fetch MCQ-passed candidates above threshold and generate personalized video interviews'
  }
}];

// ========================================
// Prepare Candidate Loop Data
// ========================================

const mergedData = $input.all();

console.log('=== PREPARING CANDIDATE LOOP FOR ROUND 2 ===');

// Extract candidates and JD
let candidates = [];
let jobRequirements = {};

// The merge node combines data into single objects with both candidate and JD fields
mergedData.forEach(item => {
  const data = item.json;

  // If it has screening_id, it's candidate data
  if (data.screening_id) {
    candidates.push(data);

    // Extract JD fields from the same merged object
    if (data.salary_budget || data.question_count || data.focus_areas) {
      jobRequirements = {
        job_title: data.job_title,
        required_skills: data.required_skills,
        optional_skills: data.optional_skills,
        experience_level: data.experience_level,
        salary_budget: data.salary_budget
      };
    }
  }
});

console.log(`âœ… Found ${candidates.length} passed candidates`);
console.log(`âœ… Job Title: ${jobRequirements.job_title || 'Unknown'}`);

// Validate we have data
if (candidates.length === 0) {
  throw new Error('No passed candidates found in database');
}

if (!jobRequirements.job_title) {
  throw new Error('No job requirements found in database');
}

// Log candidate summary
console.log('\nðŸ“Š CANDIDATE SUMMARY:');
candidates.forEach((c, idx) => {
  console.log(`  ${idx + 1}. ${c.name} - MCQ: ${c.score_percentage}%, Match: ${c.match_score}%`);
  console.log(`     Resume: ${c.resume_file_name || 'N/A'} (${c.resume_text?.length || 0} chars)`);
});

console.log('\nðŸ“‹ JOB REQUIREMENTS:');
console.log(`  Position: ${jobRequirements.job_title}`);
console.log(`  Required Skills: ${jobRequirements.required_skills}`);
console.log(`  Optional Skills: ${jobRequirements.optional_skills || 'None'}`);
console.log(`  Experience: ${jobRequirements.experience_level}`);

// Prepare data for loop
return [{
  json: {
    candidates: candidates,
    candidateCount: candidates.length,

    jobRequirements: {
      title: jobRequirements.job_title,
      description: '', // Not stored in Round 1, add if needed
      requiredSkills: jobRequirements.required_skills,
      optionalSkills: jobRequirements.optional_skills,
      experienceLevel: jobRequirements.experience_level,
      salaryBudget: jobRequirements.salary_budget
    },

    videoConfig: {
      questionsPerCandidate: 5,
      timePerQuestion: 120, // 2 minutes
      totalDuration: 600, // 10 minutes
      proctoringEnabled: true
    },

    metadata: {
      processedAt: new Date().toISOString(),
      totalCandidates: candidates.length,
      avgMCQScore: Math.round(candidates.reduce((sum, c) => sum + c.score_percentage, 0) / candidates.length),
      avgMatchScore: Math.round(candidates.reduce((sum, c) => sum + c.match_score, 0) / candidates.length),
      readyForPersonalization: true
    }
  }
}];

// ========================================
// Extract Individual Candidate Data
// ========================================

const loopData = $input.first().json;

console.log('=== PROCESSING INDIVIDUAL CANDIDATE ===');

// The candidate data is in the current item
const candidate = loopData;

// Get job requirements from the parent data
let jobRequirements = {};
let videoConfig = {};

try {
  const parentData = $('Prepare Candidate Loop').first().json;
  jobRequirements = parentData.jobRequirements;
  videoConfig = parentData.videoConfig;
} catch (error) {
  console.log('âš ï¸ Using default job requirements');
  jobRequirements = {
    title: 'Software Engineer',
    requiredSkills: 'Programming',
    experienceLevel: '2-5 years'
  };
  videoConfig = {
    questionsPerCandidate: 5,
    timePerQuestion: 120
  };
}

console.log(`\nðŸ‘¤ CANDIDATE: ${candidate.name}`);
console.log(`   Email: ${candidate.email}`);
console.log(`   MCQ Score: ${candidate.score_percentage}%`);
console.log(`   Match Score: ${candidate.match_score}%`);
console.log(`   Resume Available: ${candidate.resume_text ? 'YES' : 'NO'}`);
console.log(`   Resume Length: ${candidate.resume_text?.length || 0} characters`);

// Generate unique video assessment ID
const videoAssessmentId = `video_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

// Create expiration (3 days from now)
const expiresAt = new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString();

// Return candidate with context for AI question generation
return [{
  json: {
    // Candidate info
    screening_id: candidate.screening_id,
    video_assessment_id: videoAssessmentId,
    name: candidate.name,
    email: candidate.email,
    phone: candidate.phone || 'N/A',
    location: candidate.location || 'N/A',
    current_company: candidate.current_company || 'N/A',
    job_title: candidate.job_title || 'N/A',
    jid: candidate.jid || '',
    experience_level: candidate.experience_level || 'Unknown',

    // Resume data
    resume_text: candidate.resume_text || '',
    resume_file_name: candidate.resume_file_name || 'Resume.pdf',
    resume_drive_url: candidate.resume_drive_url || '',

    // Scores
    mcq_score: candidate.score_percentage || 0,
    match_score: candidate.match_score || 0,
    mcq_grade: candidate.grade || 'N/A',

    // Job context
    jobRequirements: jobRequirements,
    videoConfig: videoConfig,

    // Metadata
    expires_at: expiresAt,
    invited_at: new Date().toISOString(),
    status: 'video_invited'
  }
}];

// ========================================
// Generate Personalized Video Question Prompt
// ========================================

const candidateData = $input.first().json;

console.log(`\n=== GENERATING PERSONALIZED QUESTIONS FOR: ${candidateData.name} ===`);

const jd = candidateData.jobRequirements;
const config = candidateData.videoConfig;

// Create personalized AI prompt
const personalizedPrompt = `You are an expert technical interviewer. Generate exactly ${config.questionsPerCandidate} personalized video interview questions for THIS SPECIFIC CANDIDATE for the ${jd.title} position.

**CANDIDATE PROFILE:**
- Name: ${candidateData.name}
- Current Role: ${candidateData.job_title} at ${candidateData.current_company}
- Experience Level: ${candidateData.experience_level}
- MCQ Assessment Score: ${candidateData.mcq_score}% (Grade: ${candidateData.mcq_grade})
- Overall Match Score: ${candidateData.match_score}%

**CANDIDATE'S COMPLETE RESUME:**
${candidateData.resume_text}

**JOB REQUIREMENTS:**
- Position: ${jd.title}
- Required Skills: ${jd.requiredSkills}
- Optional Skills: ${jd.optionalSkills || 'None specified'}
- Experience Level: ${jd.experienceLevel}
- Salary Range: ${jd.salaryBudget || 'Competitive'}

**QUESTION GENERATION RULES:**

Generate EXACTLY ${config.questionsPerCandidate} questions with this distribution:

1. **Technical Deep Dive (Questions 1-2):** 
   - Focus on ${jd.requiredSkills}
   - Can be similar across candidates (core technical concepts)
   - Match their ${candidateData.experience_level} level
   - Test depth of knowledge

2. **Resume-Specific Questions (Questions 3-4):** 
   - MUST BE UNIQUE TO THIS CANDIDATE
   - Reference THEIR specific projects from the resume
   - Ask about THEIR work at ${candidateData.current_company}
   - Probe into THEIR specific technical achievements
   - Mention actual project names, technologies, or accomplishments from THEIR resume

3. **Problem-Solving Scenario (Question 5):**
   - Real-world problem relevant to ${jd.title}
   - Can be similar across candidates
   - Tests practical application of ${jd.requiredSkills}

**PERSONALIZATION REQUIREMENTS:**
- Questions 3 and 4 MUST reference specific details from THIS candidate's resume
- Use their actual company names, project names, or specific experiences
- Make it clear these questions are tailored to THEM
- Show you read and understood THEIR background

**ANSWER EXPECTATIONS:**
- Each question should take ${config.timePerQuestion} seconds (2 minutes) to answer
- Questions must be open-ended (no yes/no)
- Encourage detailed explanations and examples
- Test both knowledge and communication skills

**OUTPUT FORMAT (JSON ONLY, NO MARKDOWN):**
{
  "candidateId": "${candidateData.video_assessment_id}",
  "candidateName": "${candidateData.name}",
  "jobTitle": "${jd.title}",
  "generatedAt": "${new Date().toISOString()}",
  "questions": [
    {
      "questionId": 1,
      "questionText": "Your detailed question here...",
      "category": "technical_deep_dive",
      "difficulty": "medium",
      "timeLimit": ${config.timePerQuestion},
      "isPersonalized": false,
      "evaluationCriteria": [
        "Technical accuracy",
        "Depth of knowledge",
        "Clarity of explanation"
      ],
      "keyPoints": [
        "Should mention X",
        "Should explain Y",
        "Should demonstrate Z"
      ]
    },
    {
      "questionId": 2,
      "questionText": "Your detailed question here...",
      "category": "technical_deep_dive",
      "difficulty": "medium",
      "timeLimit": ${config.timePerQuestion},
      "isPersonalized": false,
      "evaluationCriteria": [...],
      "keyPoints": [...]
    },
    {
      "questionId": 3,
      "questionText": "Based on your resume, you worked on [SPECIFIC PROJECT] at ${candidateData.current_company}. Can you walk me through...",
      "category": "resume_specific",
      "difficulty": "medium",
      "timeLimit": ${config.timePerQuestion},
      "isPersonalized": true,
      "personalizedDetails": "References specific project/experience from their resume",
      "evaluationCriteria": [...],
      "keyPoints": [...]
    },
    {
      "questionId": 4,
      "questionText": "I noticed you have experience with [SPECIFIC TECHNOLOGY from resume]. How did you apply this in...",
      "category": "resume_specific",
      "difficulty": "medium",
      "timeLimit": ${config.timePerQuestion},
      "isPersonalized": true,
      "personalizedDetails": "References their specific technical experience",
      "evaluationCriteria": [...],
      "keyPoints": [...]
    },
    {
      "questionId": 5,
      "questionText": "Scenario-based problem-solving question...",
      "category": "problem_solving",
      "difficulty": "medium",
      "timeLimit": ${config.timePerQuestion},
      "isPersonalized": false,
      "evaluationCriteria": [...],
      "keyPoints": [...]
    }
  ]
}

**CRITICAL REQUIREMENTS:**
- Return ONLY valid JSON (no markdown, no code blocks)
- Questions 3 and 4 MUST be personalized with resume details
- All ${config.questionsPerCandidate} questions must be included
- Each question should be clear, professional, and answerable in ${config.timePerQuestion} seconds
- Focus heavily on ${jd.requiredSkills}
`;

console.log(`âœ… Generated prompt for ${candidateData.name}`);
console.log(`   Job: ${jd.title}`);
console.log(`   Questions: ${config.questionsPerCandidate}`);
console.log(`   Resume length: ${candidateData.resume_text?.length || 0} chars`);

return [{
  json: {
    // Pass through candidate data
    ...candidateData,

    // AI prompt
    aiPrompt: personalizedPrompt,

    // Metadata
    promptMetadata: {
      candidateName: candidateData.name,
      candidateEmail: candidateData.email,
      jobTitle: jd.title,
      questionCount: config.questionsPerCandidate,
      resumeLength: candidateData.resume_text?.length || 0,
      generatedAt: new Date().toISOString()
    }
  }
}];

// ========================================
// Parse AI Generated Questions
// ========================================

const aiResponse = $input.first().json;

console.log('=== PARSING AI GENERATED QUESTIONS ===');

// Get candidate data from previous node
let candidateData = {};
try {
  candidateData = $('Generate Personalized Question Prompt').first().json;
} catch (error) {
  console.log('âš ï¸ Could not get candidate data from previous node');
}

// Parse AI response
let questionsData;
try {
  // Try to get from different possible response formats
  if (aiResponse.output && typeof aiResponse.output === 'string') {
    // Remove markdown code blocks if present
    let cleanedOutput = aiResponse.output.trim();
    cleanedOutput = cleanedOutput.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();

    // Find JSON array/object
    const startIndex = cleanedOutput.search(/[{\[]/);
    const endIndex = cleanedOutput.lastIndexOf('}') > cleanedOutput.lastIndexOf(']') 
      ? cleanedOutput.lastIndexOf('}') 
      : cleanedOutput.lastIndexOf(']');

    if (startIndex !== -1 && endIndex !== -1) {
      cleanedOutput = cleanedOutput.substring(startIndex, endIndex + 1);
    }

    questionsData = JSON.parse(cleanedOutput);
  } else if (aiResponse.output && typeof aiResponse.output === 'object') {
    questionsData = aiResponse.output;
  } else if (typeof aiResponse === 'string') {
    questionsData = JSON.parse(aiResponse);
  } else {
    questionsData = aiResponse;
  }
} catch (error) {
  console.error('âŒ Failed to parse questions:', error.message);
  throw new Error(`Failed to parse AI response: ${error.message}`);
}

// Validate questions
const questions = questionsData.questions || [];

if (questions.length !== 5) {
  console.warn(`âš ï¸ Expected 5 questions, got ${questions.length}`);
}

console.log(`âœ… Parsed ${questions.length} questions for ${candidateData.name}`);

// Log personalization check
const personalizedQuestions = questions.filter(q => q.isPersonalized);
console.log(`   Personalized questions: ${personalizedQuestions.length}`);

questions.forEach((q, idx) => {
  console.log(`   ${idx + 1}. [${q.category}] ${q.isPersonalized ? 'â­ PERSONALIZED' : 'Standard'}`);
  console.log(`      ${q.questionText.substring(0, 80)}...`);
});

return [{
  json: {
    // Candidate data
    video_assessment_id: candidateData.video_assessment_id,
    screening_id: candidateData.screening_id,
    name: candidateData.name,
    email: candidateData.email,
    phone: candidateData.phone,
    location: candidateData.location,
    current_company: candidateData.current_company,
    job_title: candidateData.job_title,
    experience_level: candidateData.experience_level,
    match_score: candidateData.match_score,
    expires_at: candidateData.expires_at,
    invited_at: candidateData.invited_at,

    // Job requirements
    jobRequirements: candidateData.jobRequirements,

    // Generated questions
    questions: questions,
    questionsCount: questions.length,
    personalizedQuestionsCount: personalizedQuestions.length,

    // Metadata
    questionGeneratedAt: new Date().toISOString(),
    videoConfig: candidateData.videoConfig
  }
}];

// Prepare Video Interview Email
let candidateData = {};
try {
  candidateData = $('Parse Generated Questions').first().json;
} catch (error) {
  throw new Error('Failed to get candidate data for email');
}

const appBaseUrl = (($('Process Round 2 Form').first().json.appBaseUrl) || 'http://localhost:5173').replace(/\/$/, '');
const videoInterviewUrl = `${appBaseUrl}/candidate-portal/assessment-instructions?id=${encodeURIComponent(candidateData.video_assessment_id)}&flow=video`;

const emailHTML = `
<div style="font-family: 'Segoe UI', Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; background: #f8f9fa;">
  <div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 30px; border-radius: 12px; text-align: center; margin-bottom: 25px;">
    <h1 style="margin: 0; font-size: 24px;">Video Interview Invitation - Round 2</h1>
    <p style="margin: 10px 0 0 0; font-size: 16px; opacity: 0.9;">${candidateData.jobRequirements.title} Position</p>
  </div>

  <div style="background: white; padding: 25px; border-radius: 8px; margin-bottom: 20px; border-left: 4px solid #28a745;">
    <p style="margin: 0 0 15px 0; font-size: 16px;">Dear <strong>${candidateData.name}</strong>,</p>
    <p style="margin: 0; color: #495057; line-height: 1.6;">
      Congratulations on passing the MCQ assessment. You are now invited to your personalized video interview.
    </p>
  </div>

  <div style="background: #fff3cd; border: 1px solid #ffeaa7; border-radius: 8px; padding: 20px; margin-bottom: 20px;">
    <h3 style="margin: 0 0 15px 0; color: #856404;">Important Instructions</h3>
    <ul style="margin: 0; padding-left: 20px; color: #856404; font-size: 14px; line-height: 1.6;">
      <li>Ensure camera and microphone permissions are enabled.</li>
      <li>Use a stable internet connection.</li>
      <li>Complete the interview in one sitting.</li>
      <li>This link expires in 3 days.</li>
    </ul>
  </div>

  <div style="background: linear-gradient(135deg, #28a745 0%, #20c997 100%); border-radius: 8px; padding: 25px; margin-bottom: 20px; text-align: center;">
    <h3 style="margin: 0 0 15px 0; color: white;">Start Your Video Interview</h3>
    <a href="${videoInterviewUrl}" style="display: inline-block; background: white; color: #28a745; padding: 15px 40px; border-radius: 6px; text-decoration: none; font-weight: bold; margin: 10px 0; font-size: 16px;">
      Begin Video Interview
    </a>
    <p style="margin: 15px 0 0 0; font-size: 13px; color: white; opacity: 0.9;">
      <strong>Interview ID:</strong> ${candidateData.video_assessment_id}<br>
      <strong>Expires:</strong> ${new Date(candidateData.expires_at).toLocaleDateString()}
    </p>
  </div>
</div>`;

return [{
  json: {
    to: candidateData.email,
    subject: `Round 2: Your Personalized Video Interview - ${candidateData.jobRequirements.title}`,
    html: emailHTML,
    candidate_name: candidateData.name,
    video_assessment_id: candidateData.video_assessment_id,
    expires_at: candidateData.expires_at,
    interview_url: videoInterviewUrl
  }
}];

const allEmails = $input.all();

console.log('\n=== VIDEO INTERVIEW GENERATION SUMMARY ===');

const summary = {
  success: true,
  totalCandidatesProcessed: allEmails.length,
  emailsSent: allEmails.length,
  processedAt: new Date().toISOString(),

  candidates: allEmails.map(email => ({
    name: email.json.candidate_name,
    email: email.json.to,
    video_assessment_id: email.json.video_assessment_id,
    interview_url: email.json.interview_url,
    expires_at: email.json.expires_at
  })),

  status: 'completed',
  message: `Successfully processed ${allEmails.length} candidates for Round 2 video interviews`
};

console.log(`âœ… ${summary.totalCandidatesProcessed} candidates invited`);

return [{ json: summary }];

// Get the questions from Parse Generated Questions node
const questionsData = $('Parse Generated Questions').first().json.questions;
const videoAssessmentId = $('Parse Generated Questions').first().json.video_assessment_id;

// Return each question with the video_assessment_id
return questionsData.map(q => ({
  json: {
    ...q,
    video_assessment_id: videoAssessmentId
  }
}));
